#!/usr/bin/env node
// Parse vitest coverage output for PiAgent.ts branch coverage
// Returns METRIC line for branch_gap (sum of uncovered branch points, 0 = all covered)
// Reads coverage/coverage-final.json generated by vitest --coverage

import { spawnSync } from 'node:child_process';
import { readFileSync } from 'node:fs';
import { resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = resolve(fileURLToPath(import.meta.url), '..');

// Run vitest with coverage
const result = spawnSync('npx', ['vitest', 'run', '--coverage'], {
  cwd: __dirname,
  stdio: ['ignore', 'pipe', 'pipe'],
  timeout: 120_000,
});

if (result.status !== 0) {
  console.error(result.stderr.toString());
  process.exit(result.status ?? 1);
}

// Read the coverage JSON
const coveragePath = resolve(__dirname, 'coverage', 'coverage-final.json');
let coverage;
try {
  coverage = JSON.parse(readFileSync(coveragePath, 'utf-8'));
} catch {
  // Coverage file might not exist if no tests ran
  console.log('METRIC branch_gap=999');
  process.exit(0);
}

// Find PiAgent.ts and compute branch gap
let branchGap = 999;
for (const [filePath, data] of Object.entries(coverage)) {
  if (filePath.endsWith('PiAgent.ts')) {
    const b = data['b'];
    let total = 0;
    let covered = 0;
    for (const hitsList of Object.values(b)) {
      for (const hit of hitsList) {
        total++;
        if (hit > 0) covered++;
      }
    }
    branchGap = total - covered;
    break;
  }
}

console.log(`METRIC branch_gap=${branchGap}`);
process.exit(0);
